std::vector<int> bitonic_sort(const std::vector<int>& arr) {
    if (arr.empty()) {
        return {};
    }

    int n = arr.size();
    int nextPow2 = 1;
    while (nextPow2 < n) {
        nextPow2 *= 2;
    }

    // Pad the array to the next power of 2
    // We use INT_MAX for padding to handle ascending sort
    std::vector<int> padded(nextPow2, INT_MAX);
    std::copy(arr.begin(), arr.end(), padded.begin());

    bitonicSortRecursive(padded, 0, nextPow2, true);

    // Return the first n elements (trimmed back to original size)
    std::vector<int> result(n);
    std::copy(padded.begin(), padded.begin() + n, result.begin());
    return result;
}

