                compareAndSwap(&arr, i, i + k, ascending)
            }
            bitonicMerge(&arr, low, k, ascending)
            bitonicMerge(&arr, low + k, k, ascending)
        }
    }

    private static func bitonicSortRecursive(_ arr: inout [Int], _ low: Int, _ cnt: Int, _ ascending: Bool) {
